import pandas as pd
import datetime

class FinancialReportGenerator:
    def __init__(self, company_name, report_type="Income Statement", currency="$"):
        self.company_name = company_name
        self.report_type = report_type
        self.currency = currency
        self.data = None
        self.start_date = None
        self.end_date = None

    def load_data(self, data_source, source_type="CSV", **kwargs):
        """
        Loads data from various sources.

        Args:
            data_source (str): Path to the data file or database connection string.
            source_type (str): Type of data source (CSV, Excel, DataFrame, etc.).
            **kwargs: Additional keyword arguments to pass to the data loading function.
        """
        try:
            if source_type.upper() == "CSV":
                self.data = pd.read_csv(data_source, **kwargs)
            elif source_type.upper() == "EXCEL":
                self.data = pd.read_excel(data_source, **kwargs)
            elif source_type.upper() == "DATAFRAME":
                self.data = data_source  # Assume data_source is already a DataFrame
            else:
                raise ValueError(f"Unsupported data source type: {source_type}")

            # Ensure date column is datetime
            if 'date' in self.data.columns:
                self.data['date'] = pd.to_datetime(self.data['date'])

        except FileNotFoundError:
            print(f"Error: File not found at {data_source}")
            self.data = None
        except Exception as e:
            print(f"Error loading data: {e}")
            self.data = None

    def set_date_range(self, start_date=None, end_date=None):
        """
        Sets the date range for the report.  If no dates are provided, all data is used.

        Args:
            start_date (str or datetime): Start date for the report (YYYY-MM-DD).
            end_date (str or datetime): End date for the report (YYYY-MM-DD).
        """
        if start_date:
            try:
                self.start_date = pd.to_datetime(start_date)
            except ValueError:
                print("Invalid start date format.  Use YYYY-MM-DD.")
                self.start_date = None
        else:
            self.start_date = None

        if end_date:
            try:
                self.end_date = pd.to_datetime(end_date)
            except ValueError:
                print("Invalid end date format.  Use YYYY-MM-DD.")
                self.end_date = None
        else:
            self.end_date = None

    def generate_income_statement(self, revenue_accounts, expense_accounts):
        """
        Generates an income statement.

        Args:
            revenue_accounts (list): List of account names that represent revenue.
            expense_accounts (list): List of account names that represent expenses.

        Returns:
            pandas.DataFrame: Income statement data.
        """
        if self.data is None:
            print("Error: No data loaded. Please load data first.")
            return None

        df = self.data.copy()

        # Filter by date range if specified
        if self.start_date and self.end_date:
            df = df[(df['date'] >= self.start_date) & (df['date'] <= self.end_date)]
        elif self.start_date:
            df = df[df['date'] >= self.start_date]
        elif self.end_date:
            df = df[df['date'] <= self.end_date]

        total_revenue = df[df['account'].isin(revenue_accounts)]['amount'].sum()
        total_expenses = df[df['account'].isin(expense_accounts)]['amount'].sum()
        net_income = total_revenue - total_expenses

        report_data = {
            'Description': ['Revenue', 'Expenses', 'Net Income'],
            'Amount': [total_revenue, total_expenses, net_income]
        }

        report_df = pd.DataFrame(report_data)
        return report_df

    def generate_report(self, report_format="DataFrame", revenue_accounts=None, expense_accounts=None, output_file=None):
        """
        Generates the financial report based on the specified type.

        Args:
            report_format (str): Format of the report (DataFrame, CSV, Excel).
            revenue_accounts (list): List of revenue account names (for Income Statement).
            expense_accounts (list): List of expense account names (for Income Statement).
            output_file (str): Path to save the report to (optional).

        Returns:
            pandas.DataFrame or None: The generated report as a DataFrame, or None if an error occurred.
        """
        if self.report_type.lower() == "income statement":
            if revenue_accounts is None or expense_accounts is None:
                print("Error: Revenue and expense accounts must be specified for an Income Statement.")
                return None
            report_df = self.generate_income_statement(revenue_accounts, expense_accounts)
        else:
            print(f"Error: Unsupported report type: {self.report_type}")
            return None

        if report_df is None:
            return None

        if report_format.lower() == "dataframe":
            return report_df
        elif report_format.lower() == "csv":
            if output_file:
                report_df.to_csv(output_file, index=False)
                print(f"Report saved to {output_file}")
            else:
                print("Error: Output file path must be specified for CSV format.")
                return None
        elif report_format.lower() == "excel":
            if output_file:
                report_df.to_excel(output_file, index=False)
                print(f"Report saved to {output_file}")
            else:
                print("Error: Output file path must be specified for Excel format.")
                return None
        else:
            print(f"Error: Unsupported report format: {report_format}")
            return None

        return report_df

    def display_report(self, report_df):
        """
        Displays the report in a user-friendly format.

        Args:
            report_df (pandas.DataFrame): The report DataFrame.
        """
        if report_df is None:
            print("No report to display.")
            return

        print(f"\n{self.company_name} - {self.report_type}")
        if self.start_date and self.end_date:
            print(f"For the period: {self.start_date.strftime('%Y-%m-%d')} to {self.end_date.strftime('%Y-%m-%d')}")
        elif self.start_date:
            print(f"Starting from: {self.start_date.strftime('%Y-%m-%d')}")
        elif self.end_date:
            print(f"Up to: {self.end_date.strftime('%Y-%m-%d')}")
        else:
            print("For all available data.")

        print("-" * 40)
        for index, row in report_df.iterrows():
            description = row['Description']
            amount = row['Amount']
            print(f"{description}: {self.currency}{amount:,.2f}")  # Format with currency and commas
        print("-" * 40)

